module top_module(
count_value     ,  
enable  ,  
clk     ,  
reset      
);output [7:0] count_value;

     input enable, clk, reset;

    reg [7:0] count_value;

always @(posedge clk)
if (reset) begin
  count_value <= 8'b0 ;
end else if (enable) begin
  count_value <= count_value + 1;
end


endmodule
